// Nettoyage : deduplication par lien + filtre articles < 24h
const seen = new Set();
const output = [];
const cutoff = Date.now() - 24 * 60 * 60 * 1000;

for (const item of $input.all()) {
  const j = item.json;
  const link = (j.link || j.url || '').toString().trim().replace(/\/$/, '');
  if (!link || seen.has(link)) continue;

  const dateStr = j.isoDate || j.pubDate || j.date || j.published || null;
  const ts = dateStr ? Date.parse(dateStr) : NaN;
  if (!isNaN(ts) && ts < cutoff) continue;

  let source = '';
  try { source = new URL(link).hostname.replace(/^www\./, ''); } catch (e) {}

  seen.add(link);
  output.push({ json: {
    title: (j.title || '(sans titre)').toString().trim(),
    link,
    source,
    snippet: (j.contentSnippet || j.content || j.summary || '').toString().replace(/\s+/g, ' ').slice(0, 500),
    pubDate: dateStr || '',
  }});
}
return output;

// Construit la requete Gemini a partir de tous les articles nettoyes
const articles = $input.all().map(i => ({
  titre: i.json.title, source: i.json.source, lien: i.json.link,
  extrait: i.json.snippet, date: i.json.pubDate,
}));

const prompt = `Tu es un analyste tech francophone. Voici une liste d'articles publies recemment (titre, source, lien, extrait).

Pour CHAQUE article :
1. Resume-le en 1 a 2 phrases percutantes, en francais.
2. Attribue une importance : CRITIQUE, IMPORTANT ou MINEUR.
   - CRITIQUE = nouveau modele IA majeur, faille de securite critique, changement de politique/prix majeur.
   - IMPORTANT = nouvelle fonctionnalite notable, mise a jour significative, partenariat important.
   - MINEUR = actualite mineure, article de fond, mise a jour cosmetique.

Reponds UNIQUEMENT avec du JSON valide, sans texte avant ou apres, sans balises markdown.
Format EXACT :
{"articles":[{"titre":"...","source":"...","lien":"...","resume":"...","importance":"CRITIQUE"}]}

Articles a analyser :
${JSON.stringify(articles, null, 2)}`;

const body = {
  contents: [ { role: "user", parts: [ { text: prompt } ] } ],
  generationConfig: { temperature: 0.3, responseMimeType: "application/json" }
};

return [{ json: { body, count: articles.length } }];

// Parse la reponse Gemini + trie par importance
const res = $input.first().json;

let text = '';
try {
  text = res.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Reponse Gemini inattendue : ' + JSON.stringify(res).slice(0, 600));
}

text = text.trim().replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

let parsed;
try { parsed = JSON.parse(text); }
catch (e) { throw new Error('JSON Gemini invalide : ' + text.slice(0, 600)); }

const order = { CRITIQUE: 0, IMPORTANT: 1, MINEUR: 2 };
const articles = (parsed.articles || []).sort((a, b) =>
  (order[(a.importance || '').toUpperCase()] ?? 3) - (order[(b.importance || '').toUpperCase()] ?? 3)
);
return [{ json: { articles } }];

// Genere le rapport : Telegram (decoupe en morceaux <4096) + Gmail (HTML)
const articles = $input.first().json.articles || [];
const date = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
const emoji = { CRITIQUE: '🔴', IMPORTANT: '🟠', MINEUR: '⚪' };
const color = { CRITIQUE: '#e53935', IMPORTANT: '#fb8c00', MINEUR: '#9e9e9e' };

let tg = `*🗞️ Veille Tech — ${date}*\n\n`;
if (articles.length === 0) {
  tg += '_Aucune actualite notable dans les dernieres 24h._';
} else {
  for (const a of articles) {
    const e = emoji[(a.importance || '').toUpperCase()] || '⚪';
    tg += `${e} *${a.titre}*\n${a.resume}\n_${a.source}_ — [lire](${a.lien})\n\n`;
  }
}

let rows = '';
for (const a of articles) {
  const imp = (a.importance || 'MINEUR').toUpperCase();
  const c = color[imp] || '#9e9e9e';
  rows += `<div style="border-left:4px solid ${c};padding:8px 14px;margin:0 0 14px;background:#fafafa;">`
    + `<span style="font-size:11px;font-weight:bold;color:${c};">${imp}</span>`
    + `<h3 style="margin:4px 0;font-size:16px;">${a.titre}</h3>`
    + `<p style="margin:4px 0;color:#333;">${a.resume}</p>`
    + `<p style="margin:4px 0;font-size:12px;color:#777;">${a.source} — <a href="${a.lien}">Lire l'article</a></p></div>`;
}
const html = `<div style="font-family:Arial,sans-serif;max-width:640px;margin:auto;">`
  + `<h1 style="font-size:20px;">🗞️ Veille Tech — ${date}</h1>`
  + `<p style="color:#666;">${articles.length} article(s) analyse(s).</p>`
  + (rows || '<p><em>Aucune actualite notable dans les dernieres 24h.</em></p>')
  + `<hr><p style="font-size:11px;color:#aaa;">Genere automatiquement avec n8n + Gemini.</p></div>`;

// Decoupe le message Telegram en morceaux <= 4000 caracteres (limite Telegram = 4096)
const MAX = 4000;
const chunks = [];
let buf = '';
for (const bloc of tg.split('\n\n')) {
  if ((buf + bloc + '\n\n').length > MAX) {
    if (buf) chunks.push(buf.trim());
    buf = '';
  }
  buf += bloc + '\n\n';
}
if (buf.trim()) chunks.push(buf.trim());

const subject = `🗞️ Veille Tech — ${date} (${articles.length})`;

// 1 item par morceau Telegram ; html + subject copies sur chaque item
return chunks.map((c, i) => ({
  json: { telegram: c, html, subject, part: i + 1, totalParts: chunks.length }
}));
